'use client';

import { useState, useEffect } from 'react';

export default function UsersPage() {
    const [users, setUsers] = useState([]);
    const [newName, setNewName] = useState('');
    const [newEmail, setNewEmail] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [newRole, setNewRole] = useState('user'); // admin ou user (vendedor)
    const [loading, setLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState('');

    const fetchUsers = async () => {
        try {
            const res = await fetch('/api/users');
            const data = await res.json();
            setUsers(data);
        } catch (e) {
            console.error(e);
        }
    };

    useEffect(() => {
        fetchUsers();
    }, []);

    const handleCreateUser = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMsg('');
        try {
            const res = await fetch('/api/users', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name: newName, email: newEmail, password: newPassword, role: newRole }),
            });
            const data = await res.json();

            if (res.ok) {
                setNewName('');
                setNewEmail('');
                setNewPassword('');
                setNewRole('user');
                fetchUsers();
            } else {
                setErrorMsg(data.error || 'Erro ao criar usuário');
            }
        } catch (error) {
            setErrorMsg('Erro de conexão ao criar usuário');
        }
        setLoading(false);
    };

    return (
        <div className="space-y-6 max-w-4xl mx-auto py-8">
            <div>
                <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-teal-400 to-indigo-500">
                    Gerenciar Equipe (Atendentes e Admins)
                </h1>
                <p className="text-slate-400 mt-2">
                    Cadastre novos atendentes (vendedores) para acessar o painel e gerenciar as conversas da Lia, ou Administradores que podem configurar o robô.
                </p>
            </div>

            {errorMsg && (
                <div className="p-4 bg-red-500/10 border border-red-500/50 text-red-500 rounded-xl">
                    {errorMsg}
                </div>
            )}

            {/* Tabela de Usuários Atuais */}
            <div className="bg-slate-800 rounded-2xl border border-slate-700 overflow-hidden shadow-xl">
                <div className="p-6 border-b border-slate-700">
                    <h2 className="text-xl font-semibold text-white">Usuários Ativos</h2>
                </div>

                {users.length === 0 ? (
                    <div className="p-8 text-center text-slate-400">Carregando equipe...</div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left bg-slate-800">
                            <thead className="bg-slate-900 border-b border-slate-700">
                                <tr>
                                    <th className="p-4 text-slate-300 font-medium">Nome</th>
                                    <th className="p-4 text-slate-300 font-medium">Email</th>
                                    <th className="p-4 text-slate-300 font-medium">Permissão</th>
                                    <th className="p-4 text-slate-300 font-medium">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-700/50">
                                {users.map(u => (
                                    <tr key={u._id} className="hover:bg-slate-700/30 transition-colors">
                                        <td className="p-4 text-white font-medium">{u.name}</td>
                                        <td className="p-4 text-slate-300">{u.email}</td>
                                        <td className="p-4">
                                            {u.role === 'admin' ? (
                                                <span className="px-3 py-1 bg-indigo-500/20 text-indigo-300 rounded-full text-xs font-semibold border border-indigo-500/30">
                                                    Administrador
                                                </span>
                                            ) : (
                                                <span className="px-3 py-1 bg-teal-500/20 text-teal-300 rounded-full text-xs font-semibold border border-teal-500/30">
                                                    Atendente
                                                </span>
                                            )}
                                        </td>
                                        <td className="p-4">
                                            <span className="flex items-center text-sm text-green-400">
                                                <span className="w-2 h-2 rounded-full bg-emerald-500 mr-2 animate-pulse"></span> Ativo
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Formulário Novo Usuário */}
            <div className="bg-slate-800 rounded-2xl border border-slate-700 p-6 shadow-xl">
                <h2 className="text-xl font-semibold text-white mb-6">Cadastrar Novo Membro</h2>

                <form onSubmit={handleCreateUser} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-1">Nome Completo</label>
                            <input
                                type="text" required
                                value={newName} onChange={e => setNewName(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                                placeholder="Ex: João da Silva"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-1">E-mail de Acesso</label>
                            <input
                                type="email" required
                                value={newEmail} onChange={e => setNewEmail(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                                placeholder="joao@empresa.com"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-1">Senha Inicial</label>
                            <input
                                type="password" required minLength={6}
                                value={newPassword} onChange={e => setNewPassword(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                                placeholder="******"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-400 mb-1">Tipo de Acesso</label>
                            <select
                                value={newRole} onChange={e => setNewRole(e.target.value)}
                                className="w-full bg-slate-900 border border-slate-700 rounded-xl px-4 py-2.5 text-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                            >
                                <option value="user">Atendente (Conversar com Clientes)</option>
                                <option value="admin">Administrador (Configurar Robô e Usuários)</option>
                            </select>
                        </div>
                    </div>

                    <div className="pt-4 flex justify-end">
                        <button
                            type="submit"
                            disabled={loading}
                            className="px-6 py-2.5 bg-gradient-to-r from-teal-500 to-indigo-600 hover:from-teal-400 hover:to-indigo-500 text-white font-semibold rounded-xl transition-all disabled:opacity-50"
                        >
                            {loading ? 'Cadastrando...' : 'Adicionar Membro'}
                        </button>
                    </div>
                </form>
            </div>

        </div>
    );
}
